// hooks/useElementSize.ts
import { useEffect, useRef, useState } from 'react';

export function useElementSize<T extends Element>(): [React.RefObject<T>, { width: number; height: number }] {
  const ref = useRef<T>(null);
  const [size, setSize] = useState({ width: 0, height: 0 });

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    let raf = 0;

    const ro = new ResizeObserver((entries) => {
      cancelAnimationFrame(raf);
      raf = requestAnimationFrame(() => {
        const entry = entries[0];
        const { width, height } = entry.contentRect;
        setSize((prev) => {
          if (Math.abs(prev.width - width) < 1 && Math.abs(prev.height - height) < 1) return prev;
          return { width, height };
        });
      });
    });

    ro.observe(el);
    return () => { ro.disconnect(); cancelAnimationFrame(raf); };
  }, []);

  return [ref, size];
}

// components/AdaptiveChart.tsx
import { useElementSize } from '@/hooks/useElementSize';

export function AdaptiveChart({ data }: { data: number[] }) {
  const [ref, { width, height }] = useElementSize<HTMLDivElement>();
  const pointCount = Math.max(10, Math.floor(width / 20));
  const sampled = sampleData(data, pointCount);

  return (
    <div ref={ref} className="relative h-64 w-full">
      {width > 0 && (
        <svg width={width} height={height} role="img" aria-label={`Chart with ${pointCount} data points`}>
          {sampled.map((v, i) => (
            <circle key={i} cx={(i / (pointCount - 1)) * width} cy={height - v * height} r={3} fill="currentColor" />
          ))}
        </svg>
      )}
    </div>
  );
}

function sampleData(data: number[], count: number): number[] {
  if (data.length <= count) return data;
  const step = data.length / count;
  return Array.from({ length: count }, (_, i) => data[Math.floor(i * step)]);
}

