import { useState, useId } from 'react';
import { Info } from 'lucide-react';

export function InfoTooltip({ description, children }: { description: string; children: React.ReactNode }) {
  const [open, setOpen] = useState(false);
  const id = useId();

  return (
    <span className="inline-flex items-center gap-1">
      {children}
      <span className="relative">
        <button
          type="button"
          aria-label="More information"
          aria-describedby={id}
          aria-expanded={open}
          onClick={() => setOpen((o) => !o)}
          onMouseEnter={() => setOpen(true)}
          onMouseLeave={() => setOpen(false)}
          onFocus={() => setOpen(true)}
          onBlur={() => setOpen(false)}
          onKeyDown={(e) => e.key === 'Escape' && setOpen(false)}
          className="
            inline-flex h-6 w-6 items-center justify-center rounded-full text-neutral-400
            hover:bg-neutral-100 hover:text-neutral-700
            focus-visible:outline-2 focus-visible:outline-blue-500
          "
        >
          <Info className="h-4 w-4" />
        </button>
        {/* Description is always present for screen readers */}
        <span
          id={id}
          role="tooltip"
          className={`
            ${open ? 'block' : 'sr-only'}
            absolute left-1/2 top-full z-50 mt-2 -translate-x-1/2
            w-max max-w-xs rounded-md bg-neutral-900 px-3 py-2 text-xs text-white shadow-lg
            after:absolute after:bottom-full after:left-1/2 after:-translate-x-1/2 after:border-4 after:border-transparent after:border-b-neutral-900
          `}
        >
          {description}
        </span>
      </span>
    </span>
  );
}

