// hooks/useFocusScrollIntoView.ts
import { useEffect } from 'react';

export function useFocusScrollIntoView(formSelector = 'form') {
  useEffect(() => {
    const isTouchKeyboard = () => 'visualViewport' in window && window.matchMedia('(pointer: coarse)').matches;

    const onFocusIn = (e: FocusEvent) => {
      const target = e.target as HTMLElement;
      if (!target.matches('input, textarea, select')) return;

      // Delay so keyboard animation completes and visualViewport stabilizes
      setTimeout(() => {
        if (!isTouchKeyboard()) {
          target.scrollIntoView({ block: 'center', behavior: 'smooth' });
          return;
        }

        // Touch: compute visible region via visualViewport
        const vv = window.visualViewport!;
        const visibleTop = vv.offsetTop;
        const visibleBottom = vv.offsetTop + vv.height;
        const rect = target.getBoundingClientRect();

        const fullyVisible = rect.top >= visibleTop + 16 && rect.bottom <= visibleBottom - 16;
        if (fullyVisible) return;

        // Calculate desired scroll
        const desiredTop = visibleTop + (vv.height - rect.height) / 2;
        const delta = rect.top - desiredTop;
        window.scrollBy({ top: delta, behavior: 'smooth' });
      }, 300);
    };

    const form = document.querySelector(formSelector);
    if (!form) return;
    form.addEventListener('focusin', onFocusIn as EventListener);
    return () => form.removeEventListener('focusin', onFocusIn as EventListener);
  }, [formSelector]);
}

