// components/ListWithDetail.tsx
'use client';
import { useParams, useRouter } from 'next/navigation';
import { useBreakpoint } from '@/hooks/useBreakpoint';
import Link from 'next/link';

export function ListWithDetail({ children }: { children: React.ReactNode }) {
  const params = useParams() as { id?: string };
  const router = useRouter();
  const bp = useBreakpoint();
  const hasDetail = Boolean(params?.id);

  if (bp === 'mobile') {
    return hasDetail ? (
      <div className="h-dvh flex flex-col">
        <header className="flex items-center gap-2 border-b px-3 h-12">
          <button onClick={() => router.push('/users')} aria-label="Back to list" className="min-h-11 min-w-11 flex items-center justify-center">←</button>
          <h1 className="font-medium">User</h1>
        </header>
        <div className="flex-1 overflow-y-auto">{children}</div>
      </div>
    ) : (
      <UserList activeId={params?.id} />
    );
  }

  return (
    <div className="h-dvh grid grid-cols-[320px_1fr] divide-x">
      <UserList activeId={params?.id} />
      <div className="overflow-y-auto">
        {hasDetail ? children : <EmptyState />}
      </div>
    </div>
  );
}

function UserList({ activeId }: { activeId?: string }) {
  const users = [{ id: 'abc-123', name: 'Alice' }, { id: 'def-456', name: 'Bob' }];
  return (
    <ul className="overflow-y-auto">
      {users.map((u) => (
        <li key={u.id}>
          <Link
            href={`/users/${u.id}`}
            aria-current={activeId === u.id ? 'page' : undefined}
            className="flex min-h-12 items-center px-4 hover:bg-neutral-50 aria-[current=page]:bg-blue-50 aria-[current=page]:text-blue-900"
          >{u.name}</Link>
        </li>
      ))}
    </ul>
  );
}

function EmptyState() {
  return <div className="flex h-full items-center justify-center text-neutral-500">Select a user from the list</div>;
}

// components/TableControls.tsx
'use client';
import { useState } from 'react';
import { useBreakpoint } from '@/hooks/useBreakpoint';
import { Filter, Search, X } from 'lucide-react';

type Filters = { search: string; status: string[]; dateRange: string };

export function TableControls({ filters, onChange }: { filters: Filters; onChange: (f: Filters) => void }) {
  const bp = useBreakpoint();
  const [sheetOpen, setSheetOpen] = useState(false);
  const filterCount = (filters.status.length ? 1 : 0) + (filters.dateRange ? 1 : 0);

  const SearchInput = (
    <div className="relative flex-1 min-w-0">
      <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-neutral-400" aria-hidden />
      <input
        type="search"
        value={filters.search}
        onChange={(e) => onChange({ ...filters, search: e.target.value })}
        placeholder="Search"
        aria-label="Search table"
        className="w-full min-h-10 rounded border bg-white pl-9 pr-3 text-sm"
      />
    </div>
  );

  if (bp === 'mobile') {
    return (
      <div className="flex items-center gap-2 px-4 py-3">
        {SearchInput}
        <button
          type="button"
          onClick={() => setSheetOpen(true)}
          className="relative flex h-10 min-w-10 items-center justify-center rounded border bg-white"
          aria-label="Open filters"
        >
          <Filter className="h-4 w-4" />
          {filterCount > 0 && <span className="absolute -top-1 -right-1 flex h-4 w-4 items-center justify-center rounded-full bg-blue-500 text-[10px] text-white">{filterCount}</span>}
        </button>
        {sheetOpen && <FilterSheet filters={filters} onChange={onChange} onClose={() => setSheetOpen(false)} />}
      </div>
    );
  }

  return (
    <div className="flex flex-wrap items-center gap-2 px-4 py-3">
      {SearchInput}
      <StatusFilter value={filters.status} onChange={(s) => onChange({ ...filters, status: s })} />
      <DateFilter value={filters.dateRange} onChange={(d) => onChange({ ...filters, dateRange: d })} />
      {filterCount > 0 && (
        <button type="button" onClick={() => onChange({ search: '', status: [], dateRange: '' })} className="text-sm text-blue-600 hover:underline">
          Clear all
        </button>
      )}
    </div>
  );
}

function FilterSheet({ filters, onChange, onClose }: any) {
  return (
    <div className="fixed inset-0 z-50">
      <div className="absolute inset-0 bg-black/50" onClick={onClose} />
      <div
        role="dialog"
        aria-modal="true"
        aria-label="Filters"
        className="absolute inset-x-0 bottom-0 max-h-[85dvh] overflow-y-auto rounded-t-2xl bg-white"
        style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}
      >
        <header className="sticky top-0 flex items-center justify-between border-b bg-white px-4 py-3">
          <h2 className="font-semibold">Filters</h2>
          <button type="button" onClick={onClose} aria-label="Close" className="flex h-11 w-11 items-center justify-center"><X /></button>
        </header>
        <div className="space-y-6 p-4">
          <section>
            <h3 className="mb-2 text-sm font-medium">Status</h3>
            <StatusFilter value={filters.status} onChange={(s: string[]) => onChange({ ...filters, status: s })} expanded />
          </section>
          <section>
            <h3 className="mb-2 text-sm font-medium">Date</h3>
            <DateFilter value={filters.dateRange} onChange={(d: string) => onChange({ ...filters, dateRange: d })} expanded />
          </section>
        </div>
        <footer className="sticky bottom-0 border-t bg-white p-4" style={{ paddingBottom: 'max(1rem, env(safe-area-inset-bottom))' }}>
          <button type="button" onClick={onClose} className="w-full min-h-12 rounded-lg bg-black text-white font-medium">Apply</button>
        </footer>
      </div>
    </div>
  );
}

function StatusFilter(props: any) { return <button className="min-h-10 rounded border bg-white px-3 text-sm">Status</button>; }
function DateFilter(props: any) { return <button className="min-h-10 rounded border bg-white px-3 text-sm">Date</button>; }

// components/AddressForm.tsx
import { useState } from 'react';
import { useBreakpoint } from '@/hooks/useBreakpoint';

type Country = 'US' | 'UK' | 'DE';
type Address = { line1: string; line2: string; city: string; state: string; postcode: string; country: Country; houseNumber?: string };

export function AddressForm({ value, onChange }: { value: Address; onChange: (a: Address) => void }) {
  const bp = useBreakpoint();
  const isWide = bp === 'desktop' || bp === 'wide';

  return (
    <form className="space-y-4" onSubmit={(e) => e.preventDefault()}>
      <label className="block">
        <span className="text-sm font-medium">Country</span>
        <select
          value={value.country}
          onChange={(e) => onChange({ ...value, country: e.target.value as Country })}
          autoComplete="country"
          className="mt-1 block w-full min-h-11 rounded border px-3 text-base"
        >
          <option value="US">United States</option>
          <option value="UK">United Kingdom</option>
          <option value="DE">Germany</option>
        </select>
      </label>

      {value.country === 'DE' && isWide ? (
        <div className="grid grid-cols-[1fr_120px] gap-3">
          <Field label="Street" autoComplete="address-line1" value={value.line1} onChange={(v) => onChange({ ...value, line1: v })} />
          <Field label="House nr." autoComplete="address-line2" value={value.houseNumber ?? ''} onChange={(v) => onChange({ ...value, houseNumber: v })} />
        </div>
      ) : (
        <>
          <Field label="Address line 1" autoComplete="address-line1" value={value.line1} onChange={(v) => onChange({ ...value, line1: v })} />
          {value.country === 'DE' && (
            <Field label="House number" autoComplete="address-line2" value={value.houseNumber ?? ''} onChange={(v) => onChange({ ...value, houseNumber: v })} />
          )}
        </>
      )}

      <Field label="Address line 2 (optional)" autoComplete="address-line2" value={value.line2} onChange={(v) => onChange({ ...value, line2: v })} />

      {value.country === 'US' && isWide ? (
        <div className="grid grid-cols-[2fr_1fr_1fr] gap-3">
          <Field label="City" autoComplete="address-level2" value={value.city} onChange={(v) => onChange({ ...value, city: v })} />
          <Field label="State" autoComplete="address-level1" value={value.state} onChange={(v) => onChange({ ...value, state: v })} />
          <Field label="ZIP" autoComplete="postal-code" inputMode="numeric" value={value.postcode} onChange={(v) => onChange({ ...value, postcode: v })} />
        </div>
      ) : value.country === 'UK' && isWide ? (
        <div className="grid grid-cols-[2fr_1fr] gap-3">
          <Field label="City" autoComplete="address-level2" value={value.city} onChange={(v) => onChange({ ...value, city: v })} />
          <Field label="Postcode" autoComplete="postal-code" value={value.postcode} onChange={(v) => onChange({ ...value, postcode: v })} />
        </div>
      ) : (
        <>
          <Field label="City" autoComplete="address-level2" value={value.city} onChange={(v) => onChange({ ...value, city: v })} />
          {value.country === 'US' && <Field label="State" autoComplete="address-level1" value={value.state} onChange={(v) => onChange({ ...value, state: v })} />}
          <Field label={value.country === 'US' ? 'ZIP' : 'Postcode'} autoComplete="postal-code" inputMode={value.country === 'US' ? 'numeric' : 'text'} value={value.postcode} onChange={(v) => onChange({ ...value, postcode: v })} />
        </>
      )}
    </form>
  );
}

function Field({ label, autoComplete, inputMode, value, onChange }: { label: string; autoComplete: string; inputMode?: any; value: string; onChange: (v: string) => void }) {
  return (
    <label className="block">
      <span className="text-sm font-medium">{label}</span>
      <input
        type="text"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        autoComplete={autoComplete}
        inputMode={inputMode}
        className="mt-1 block w-full min-h-11 rounded border px-3 text-base"
      />
    </label>
  );
}

// components/LazyImage.tsx
import { useEffect, useRef, useState } from 'react';

export function LazyImage({ src, alt, width, height, sizes, srcSet, placeholder }: {
  src: string;
  alt: string;
  width: number;
  height: number;
  sizes?: string;
  srcSet?: string;
  placeholder?: string; // LQIP base64 or color
}) {
  const ref = useRef<HTMLImageElement>(null);
  const [visible, setVisible] = useState(false);
  const [loaded, setLoaded] = useState(false);

  // Detect native support; if missing, use IntersectionObserver
  useEffect(() => {
    if ('loading' in HTMLImageElement.prototype) return; // native
    const img = ref.current;
    if (!img) return;
    const io = getSharedObserver();
    io.observe(img, () => setVisible(true));
    return () => io.unobserve(img);
  }, []);

  const useNative = typeof window !== 'undefined' && 'loading' in HTMLImageElement.prototype;
  const actualSrc = useNative || visible ? src : undefined;

  return (
    <div
      className="relative overflow-hidden bg-neutral-100"
      style={{ aspectRatio: `${width} / ${height}`, backgroundColor: placeholder?.startsWith('#') ? placeholder : undefined }}
    >
      {placeholder && placeholder.startsWith('data:') && !loaded && (
        <img src={placeholder} alt="" aria-hidden className="absolute inset-0 h-full w-full object-cover blur-md scale-110" />
      )}
      <img
        ref={ref}
        src={actualSrc}
        srcSet={actualSrc ? srcSet : undefined}
        sizes={sizes}
        alt={alt}
        width={width}
        height={height}
        loading="lazy"
        decoding="async"
        onLoad={() => setLoaded(true)}
        className={`absolute inset-0 h-full w-full object-cover transition-opacity duration-500 ${loaded ? 'opacity-100' : 'opacity-0'}`}
      />
    </div>
  );
}

// Shared observer pattern
type Callback = () => void;
let sharedObserver: { observe: (el: Element, cb: Callback) => void; unobserve: (el: Element) => void } | null = null;
const callbacks = new WeakMap<Element, Callback>();

function getSharedObserver() {
  if (sharedObserver) return sharedObserver;
  const io = new IntersectionObserver(
    (entries) => {
      entries.forEach((e) => {
        if (e.isIntersecting) {
          callbacks.get(e.target)?.();
          io.unobserve(e.target);
          callbacks.delete(e.target);
        }
      });
    },
    { rootMargin: '200px 0px' }
  );
  sharedObserver = {
    observe: (el, cb) => { callbacks.set(el, cb); io.observe(el); },
    unobserve: (el) => { io.unobserve(el); callbacks.delete(el); },
  };
  return sharedObserver;
}

