'use client';
import { useState } from 'react';
import Link from 'next/link';
import { ChevronRight, MoreHorizontal } from 'lucide-react';

type Crumb = { label: string; href: string };

export function Breadcrumbs({ items }: { items: Crumb[] }) {
  const [overflowOpen, setOverflowOpen] = useState(false);

  if (items.length === 0) return null;
  const first = items[0];
  const last = items[items.length - 1];
  const middle = items.slice(1, -1);

  return (
    <nav aria-label="Breadcrumb" className="@container/breadcrumb w-full">
      <ol className="flex items-center gap-1 text-sm overflow-hidden">
        <li className="flex items-center gap-1 min-w-0">
          <Link href={first.href} className="truncate text-neutral-600 hover:text-black">{first.label}</Link>
        </li>

        {/* Middle crumbs — hidden below 768 */}
        {middle.length > 0 && (
          <>
            {/* Overflow indicator — visible below 768 */}
            <li className="@min-[768px]/breadcrumb:hidden flex items-center gap-1 relative">
              <ChevronRight className="h-3 w-3 text-neutral-400" aria-hidden />
              <button
                type="button"
                onClick={() => setOverflowOpen((o) => !o)}
                aria-label="Show hidden crumbs"
                aria-expanded={overflowOpen}
                className="flex h-6 w-6 items-center justify-center rounded hover:bg-neutral-100"
              >
                <MoreHorizontal className="h-4 w-4" />
              </button>
              {overflowOpen && (
                <div
                  role="menu"
                  className="absolute left-0 top-full z-30 mt-1 min-w-[12rem] rounded-md border bg-white shadow-lg"
                >
                  {middle.map((c) => (
                    <Link
                      key={c.href}
                      href={c.href}
                      role="menuitem"
                      onClick={() => setOverflowOpen(false)}
                      className="block px-3 py-2 text-sm hover:bg-neutral-50"
                    >{c.label}</Link>
                  ))}
                </div>
              )}
            </li>

            {/* Inline crumbs — visible at 768+ */}
            {middle.map((c) => (
              <li key={c.href} className="hidden @min-[768px]/breadcrumb:flex items-center gap-1 min-w-0">
                <ChevronRight className="h-3 w-3 text-neutral-400" aria-hidden />
                <Link href={c.href} className="truncate text-neutral-600 hover:text-black">{c.label}</Link>
              </li>
            ))}
          </>
        )}

        <li className="flex items-center gap-1 min-w-0">
          <ChevronRight className="h-3 w-3 text-neutral-400" aria-hidden />
          <span aria-current="page" className="truncate font-medium text-black">{last.label}</span>
        </li>
      </ol>
    </nav>
  );
}

// components/AdaptiveMenu.tsx
'use client';
import { useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useBreakpoint } from '@/hooks/useBreakpoint';
import { MoreVertical } from 'lucide-react';

type Item = { id: string; label: string; onSelect: () => void; destructive?: boolean };

export function AdaptiveMenu({ items, label = 'Actions' }: { items: Item[]; label?: string }) {
  const bp = useBreakpoint();
  const [open, setOpen] = useState(false);
  const triggerRef = useRef<HTMLButtonElement>(null);

  useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent) => e.key === 'Escape' && setOpen(false);
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [open]);

  const isMobile = bp === 'mobile';

  return (
    <>
      <button
        ref={triggerRef}
        type="button"
        onClick={() => setOpen((o) => !o)}
        aria-label={label}
        aria-haspopup="menu"
        aria-expanded={open}
        className="flex h-11 w-11 items-center justify-center rounded hover:bg-neutral-100"
      >
        <MoreVertical className="h-5 w-5" />
      </button>
      {open && createPortal(
        isMobile ? (
          <MobileSheet items={items} onClose={() => setOpen(false)} />
        ) : (
          <DesktopDropdown items={items} anchorRef={triggerRef} onClose={() => setOpen(false)} />
        ),
        document.body,
      )}
    </>
  );
}

function MobileSheet({ items, onClose }: { items: Item[]; onClose: () => void }) {
  return (
    <>
      <div className="fixed inset-0 z-50 bg-black/50" onClick={onClose} />
      <div
        role="menu"
        className="fixed inset-x-0 bottom-0 z-50 rounded-t-2xl bg-white"
        style={{ paddingBottom: 'max(0.5rem, env(safe-area-inset-bottom))' }}
      >
        <div className="flex justify-center py-2"><div className="h-1 w-10 rounded-full bg-neutral-300" /></div>
        <div className="divide-y">
          {items.map((item) => (
            <button
              key={item.id}
              role="menuitem"
              onClick={() => { item.onSelect(); onClose(); }}
              className={`
                w-full min-h-14 px-4 text-left text-base
                ${item.destructive ? 'text-red-600' : ''}
              `}
            >{item.label}</button>
          ))}
        </div>
        <button onClick={onClose} className="mt-2 mx-4 mb-2 min-h-12 w-[calc(100%-2rem)] rounded-lg bg-neutral-100 font-medium">Cancel</button>
      </div>
    </>
  );
}

function DesktopDropdown({ items, anchorRef, onClose }: { items: Item[]; anchorRef: React.RefObject<HTMLButtonElement>; onClose: () => void }) {
  const [pos, setPos] = useState<{ top: number; left: number } | null>(null);
  useEffect(() => {
    if (!anchorRef.current) return;
    const r = anchorRef.current.getBoundingClientRect();
    const top = r.bottom + 4;
    const left = Math.max(8, Math.min(r.right - 200, window.innerWidth - 208));
    setPos({ top, left });
  }, [anchorRef]);

  if (!pos) return null;
  return (
    <>
      <div className="fixed inset-0 z-40" onClick={onClose} />
      <div
        role="menu"
        className="fixed z-50 w-50 min-w-[12rem] rounded-md border bg-white py-1 shadow-lg"
        style={{ top: pos.top, left: pos.left }}
      >
        {items.map((item) => (
          <button
            key={item.id}
            role="menuitem"
            onClick={() => { item.onSelect(); onClose(); }}
            className={`
              block w-full px-3 py-1.5 text-left text-sm
              ${item.destructive ? 'text-red-600' : ''}
              hover:bg-neutral-50
            `}
          >{item.label}</button>
        ))}
      </div>
    </>
  );
}

