// hooks/useDpr.ts
import { useEffect, useState } from 'react';

export function useDpr(): number {
  const [dpr, setDpr] = useState(typeof window === 'undefined' ? 1 : window.devicePixelRatio);

  useEffect(() => {
    let mql: MediaQueryList;
    const setup = () => {
      mql = window.matchMedia(`(resolution: ${window.devicePixelRatio}dppx)`);
      mql.addEventListener('change', onChange);
    };
    const onChange = () => {
      setDpr(window.devicePixelRatio);
      mql.removeEventListener('change', onChange);
      setup();
    };
    setup();
    return () => mql?.removeEventListener('change', onChange);
  }, []);

  return dpr;
}

// components/Chart.tsx
import { useEffect, useRef } from 'react';
import { useDpr } from '@/hooks/useDpr';
import { useElementSize } from '@/hooks/useElementSize'; // from responsive-031

export function Chart({ data }: { data: number[] }) {
  const [containerRef, { width, height }] = useElementSize<HTMLDivElement>();
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dpr = useDpr();

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || width === 0) return;

    // Set backing store size for sharp rendering
    canvas.width = Math.round(width * dpr);
    canvas.height = Math.round(height * dpr);
    // Set CSS size (logical pixels)
    canvas.style.width = `${width}px`;
    canvas.style.height = `${height}px`;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Scale all drawing operations by DPR
    ctx.scale(dpr, dpr);

    // Draw chart (using CSS-pixel coordinates)
    ctx.strokeStyle = '#3b82f6';
    ctx.lineWidth = 2;
    ctx.beginPath();
    data.forEach((v, i) => {
      const x = (i / (data.length - 1)) * width;
      const y = height - v * height;
      if (i === 0) ctx.moveTo(x, y);
      else ctx.lineTo(x, y);
    });
    ctx.stroke();
  }, [width, height, dpr, data]);

  return (
    <div ref={containerRef} className="relative h-64 w-full">
      <canvas ref={canvasRef} role="img" aria-label="Performance chart" />
    </div>
  );
}

