// hooks/usePullToRefresh.ts
import { useEffect, useRef, useState } from 'react';

export function usePullToRefresh(scrollContainerRef: React.RefObject<HTMLElement>, onRefresh: () => Promise<void>) {
  const [pullDistance, setPullDistance] = useState(0);
  const [refreshing, setRefreshing] = useState(false);
  const startY = useRef<number | null>(null);
  const THRESHOLD = 80;

  useEffect(() => {
    const el = scrollContainerRef.current;
    if (!el) return;

    const onPointerDown = (e: PointerEvent) => {
      if (e.pointerType !== 'touch') return;
      if (el.scrollTop > 0) return;
      startY.current = e.clientY;
    };

    const onPointerMove = (e: PointerEvent) => {
      if (startY.current === null || e.pointerType !== 'touch') return;
      const dy = e.clientY - startY.current;
      if (dy < 0) { setPullDistance(0); return; }
      const damped = Math.min(dy, THRESHOLD * 1.5) * 0.6;
      setPullDistance(damped);
    };

    const onPointerUp = async () => {
      if (startY.current === null) return;
      if (pullDistance >= THRESHOLD) {
        setRefreshing(true);
        await onRefresh();
        setRefreshing(false);
      }
      setPullDistance(0);
      startY.current = null;
    };

    el.addEventListener('pointerdown', onPointerDown, { passive: true });
    el.addEventListener('pointermove', onPointerMove, { passive: true });
    el.addEventListener('pointerup', onPointerUp);
    el.addEventListener('pointercancel', onPointerUp);

    return () => {
      el.removeEventListener('pointerdown', onPointerDown);
      el.removeEventListener('pointermove', onPointerMove);
      el.removeEventListener('pointerup', onPointerUp);
      el.removeEventListener('pointercancel', onPointerUp);
    };
  }, [scrollContainerRef, pullDistance, onRefresh]);

  return { pullDistance, refreshing, isTriggered: pullDistance >= THRESHOLD };
}

// components/PullToRefresh.tsx
import { useRef } from 'react';
import { usePullToRefresh } from '@/hooks/usePullToRefresh';
import { RefreshCw } from 'lucide-react';

export function PullToRefresh({ onRefresh, children }: { onRefresh: () => Promise<void>; children: React.ReactNode }) {
  const ref = useRef<HTMLDivElement>(null);
  const { pullDistance, refreshing, isTriggered } = usePullToRefresh(ref, onRefresh);

  return (
    <div
      ref={ref}
      className="relative h-dvh overflow-y-auto overscroll-y-contain"
      style={{ touchAction: 'pan-y' }}
    >
      <div
        className="flex items-center justify-center absolute inset-x-0"
        style={{
          top: 0,
          height: pullDistance,
          transform: refreshing ? 'translateY(0)' : `translateY(-${100 - (pullDistance / 80) * 100}%)`,
        }}
        aria-live="polite"
      >
        <RefreshCw className={`h-6 w-6 text-blue-500 ${refreshing ? 'animate-spin' : isTriggered ? 'rotate-180 transition-transform' : ''}`} />
      </div>
      <div style={{ transform: `translateY(${refreshing ? 60 : pullDistance}px)`, transition: refreshing || pullDistance === 0 ? 'transform 200ms' : 'none' }}>
        {children}
      </div>
    </div>
  );
}

// components/StepForm.tsx
import { useRef, useState } from 'react';

type Field = { name: string; label: string; type: string; autoComplete?: string };
type Step = { id: string; title: string; fields: Field[] };

export function StepForm({ steps, onComplete }: { steps: Step[]; onComplete: (data: Record<string, string>) => void }) {
  const [stepIdx, setStepIdx] = useState(0);
  const [data, setData] = useState<Record<string, string>>({});
  const formRef = useRef<HTMLFormElement>(null);
  const currentStep = steps[stepIdx];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (stepIdx < steps.length - 1) {
      setStepIdx(stepIdx + 1);
      // Focus first field of next step
      requestAnimationFrame(() => {
        const firstInput = formRef.current?.querySelector<HTMLInputElement>('input');
        firstInput?.focus();
      });
    } else {
      onComplete(data);
    }
  };

  return (
    <form ref={formRef} onSubmit={handleSubmit} className="space-y-4">
      <h2 className="text-lg font-semibold">{currentStep.title}</h2>
      {currentStep.fields.map((field, i) => {
        const isLast = i === currentStep.fields.length - 1;
        const isLastStep = stepIdx === steps.length - 1;
        const enterKeyHint = isLast ? (isLastStep ? 'send' : 'next') : 'next';
        return (
          <label key={field.name} className="block">
            <span className="text-sm font-medium">{field.label}</span>
            <input
              type={field.type}
              name={field.name}
              autoComplete={field.autoComplete}
              enterKeyHint={enterKeyHint as any}
              value={data[field.name] ?? ''}
              onChange={(e) => setData({ ...data, [field.name]: e.target.value })}
              required
              className="mt-1 block w-full min-h-11 rounded border px-3 text-base"
            />
          </label>
        );
      })}
      <button
        type="submit"
        className="w-full min-h-12 rounded-lg bg-black text-white font-medium"
      >
        {stepIdx < steps.length - 1 ? 'Continue' : 'Submit'}
      </button>
    </form>
  );
}

