import { useState } from 'react';
import { useBreakpoint } from '@/hooks/useBreakpoint';
import { Pencil, Eraser, Square, Circle, Type, MoreHorizontal } from 'lucide-react';

type Tool = { id: string; label: string; icon: React.ComponentType<{ className?: string }>; shortcut?: string; priority: number };

const tools: Tool[] = [
  { id: 'pencil', label: 'Pencil', icon: Pencil, shortcut: 'B', priority: 1 },
  { id: 'eraser', label: 'Eraser', icon: Eraser, shortcut: 'E', priority: 1 },
  { id: 'rect', label: 'Rectangle', icon: Square, shortcut: 'R', priority: 2 },
  { id: 'circle', label: 'Circle', icon: Circle, shortcut: 'O', priority: 2 },
  { id: 'text', label: 'Text', icon: Type, shortcut: 'T', priority: 2 },
];

export function Palette({ active, onSelect }: { active: string; onSelect: (id: string) => void }) {
  const bp = useBreakpoint();
  const [overflow, setOverflow] = useState(false);

  if (bp === 'mobile') {
    const primary = tools.filter((t) => t.priority === 1);
    const rest = tools.filter((t) => t.priority > 1);
    return (
      <div
        className="fixed left-1/2 -translate-x-1/2 z-30 flex items-center gap-1 rounded-full border bg-white p-1 shadow-lg"
        style={{ bottom: 'calc(env(safe-area-inset-bottom) + 1rem)' }}
      >
        {primary.map((t) => <ToolButton key={t.id} tool={t} active={active === t.id} onSelect={onSelect} />)}
        <button onClick={() => setOverflow((o) => !o)} aria-label="More tools" className="flex h-11 w-11 items-center justify-center rounded-full hover:bg-neutral-100">
          <MoreHorizontal className="h-5 w-5" />
        </button>
        {overflow && (
          <div className="absolute bottom-full right-0 mb-2 flex flex-col gap-1 rounded-2xl border bg-white p-1 shadow-lg">
            {rest.map((t) => <ToolButton key={t.id} tool={t} active={active === t.id} onSelect={(id) => { onSelect(id); setOverflow(false); }} />)}
          </div>
        )}
      </div>
    );
  }

  if (bp === 'tablet') {
    return (
      <aside className="flex flex-col gap-1 border-r bg-white p-2">
        {tools.map((t) => <ToolButton key={t.id} tool={t} active={active === t.id} onSelect={onSelect} />)}
      </aside>
    );
  }

  return (
    <header className="flex items-center gap-1 border-b bg-white p-2">
      {tools.map((t) => <ToolButton key={t.id} tool={t} active={active === t.id} onSelect={onSelect} desktop />)}
    </header>
  );
}

function ToolButton({ tool, active, onSelect, desktop }: { tool: Tool; active: boolean; onSelect: (id: string) => void; desktop?: boolean }) {
  const Icon = tool.icon;
  return (
    <button
      type="button"
      onClick={() => onSelect(tool.id)}
      aria-label={tool.label}
      aria-pressed={active}
      title={desktop ? `${tool.label} (${tool.shortcut})` : tool.label}
      className={`
        flex h-11 w-11 items-center justify-center rounded
        ${active ? 'bg-blue-500 text-white' : 'hover:bg-neutral-100'}
      `}
    >
      <Icon className="h-5 w-5" />
    </button>
  );
}

