'use client';
import { useState } from 'react';
import { useBreakpoint } from '@/hooks/useBreakpoint';
import { Menu } from 'lucide-react';

export function ChatLayout({ workspaces, channels, conversation }: {
  workspaces: React.ReactNode;
  channels: React.ReactNode;
  conversation: React.ReactNode;
}) {
  const bp = useBreakpoint();
  const [channelsOpen, setChannelsOpen] = useState(false);
  const [workspacesOpen, setWorkspacesOpen] = useState(false);

  if (bp === 'desktop' || bp === 'wide') {
    return (
      <div className="grid h-dvh grid-cols-[64px_260px_1fr] divide-x">
        <aside className="overflow-y-auto bg-neutral-900 text-white">{workspaces}</aside>
        <aside className="overflow-y-auto bg-neutral-50">{channels}</aside>
        <main className="overflow-y-auto">{conversation}</main>
      </div>
    );
  }

  if (bp === 'tablet') {
    return (
      <div className="grid h-dvh grid-cols-[240px_1fr] divide-x">
        <aside className="overflow-y-auto bg-neutral-50">
          <header className="flex items-center gap-2 border-b px-3 py-2">
            <button onClick={() => setWorkspacesOpen(true)} aria-label="Switch workspace" className="flex h-11 w-11 items-center justify-center rounded hover:bg-neutral-200"><Menu className="h-5 w-5" /></button>
          </header>
          {channels}
        </aside>
        <main className="overflow-y-auto">{conversation}</main>
        {workspacesOpen && <Drawer side="left" onClose={() => setWorkspacesOpen(false)}>{workspaces}</Drawer>}
      </div>
    );
  }

  // mobile
  return (
    <div className="flex h-dvh flex-col">
      <header className="flex items-center gap-2 border-b px-3 py-2">
        <button onClick={() => setChannelsOpen(true)} aria-label="Open channels" className="flex h-11 w-11 items-center justify-center"><Menu className="h-5 w-5" /></button>
        <h1 className="font-medium">Channel name</h1>
      </header>
      <main className="flex-1 overflow-y-auto">{conversation}</main>
      <nav className="flex border-t bg-white" aria-label="Workspaces" style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}>
        {workspaces}
      </nav>
      {channelsOpen && <Drawer side="left" onClose={() => setChannelsOpen(false)}>{channels}</Drawer>}
    </div>
  );
}

function Drawer({ side, onClose, children }: { side: 'left' | 'right'; onClose: () => void; children: React.ReactNode }) {
  return (
    <>
      <div className="fixed inset-0 z-40 bg-black/50" onClick={onClose} />
      <aside
        role="dialog"
        aria-modal="true"
        className={`fixed inset-y-0 ${side === 'left' ? 'left-0' : 'right-0'} z-50 w-72 max-w-[85vw] bg-white shadow-xl overflow-y-auto`}
        style={{ paddingTop: 'env(safe-area-inset-top)' }}
      >
        {children}
      </aside>
    </>
  );
}

