// components/PasswordField.tsx
import { useState } from 'react';
import { Eye, EyeOff } from 'lucide-react';

function strength(pw: string): { score: 0 | 1 | 2 | 3 | 4; label: string } {
  let s = 0;
  if (pw.length >= 8) s++;
  if (/[A-Z]/.test(pw) && /[a-z]/.test(pw)) s++;
  if (/\d/.test(pw)) s++;
  if (/[^A-Za-z0-9]/.test(pw)) s++;
  return { score: Math.min(s, 4) as 0 | 1 | 2 | 3 | 4, label: ['Too weak', 'Weak', 'Fair', 'Good', 'Strong'][s] };
}

export function PasswordField({ value, onChange, label, error }: { value: string; onChange: (v: string) => void; label: string; error?: string }) {
  const [visible, setVisible] = useState(false);
  const { score, label: strengthLabel } = strength(value);

  return (
    <label className="block">
      <span className="text-sm font-medium">{label}</span>
      <div className="relative mt-1">
        <input
          type={visible ? 'text' : 'password'}
          value={value}
          onChange={(e) => onChange(e.target.value)}
          autoComplete="new-password"
          aria-describedby="pw-strength pw-error"
          aria-invalid={Boolean(error)}
          className="
            block w-full min-h-11 rounded border bg-white pl-3 pr-12 text-base
            focus:outline-2 focus:outline-blue-500
            aria-invalid:border-red-500
          "
        />
        <button
          type="button"
          onClick={() => setVisible((v) => !v)}
          aria-label={visible ? 'Hide password' : 'Show password'}
          aria-pressed={visible}
          className="absolute right-1 top-1/2 -translate-y-1/2 flex h-9 w-9 items-center justify-center rounded text-neutral-500 hover:bg-neutral-100"
        >
          {visible ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
        </button>
      </div>

      {/* Strength meter — flex distributes evenly */}
      <div className="mt-1.5" id="pw-strength" role="progressbar" aria-valuenow={score} aria-valuemin={0} aria-valuemax={4} aria-label={`Password strength: ${strengthLabel}`}>
        <div className="flex gap-1">
          {[0, 1, 2, 3].map((i) => (
            <div
              key={i}
              className={`h-1 flex-1 rounded ${
                i < score
                  ? score < 2 ? 'bg-red-500' : score < 3 ? 'bg-orange-400' : score < 4 ? 'bg-yellow-400' : 'bg-green-500'
                  : 'bg-neutral-200'
              }`}
            />
          ))}
        </div>
        <p className="mt-1 text-xs text-neutral-600">{value ? strengthLabel : 'At least 8 characters, mixed case, number, symbol'}</p>
      </div>

      {/* Error message — reserved min-height to prevent CLS */}
      <p id="pw-error" role={error ? 'alert' : undefined} className="min-h-[1.25rem] mt-1 text-sm text-red-600">{error ?? ''}</p>
    </label>
  );
}

