// components/CommandPalette.tsx
'use client';
import { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { useBreakpoint } from '@/hooks/useBreakpoint';
import { Search, X } from 'lucide-react';

type Command = { id: string; label: string; group: string; onSelect: () => void; shortcut?: string };

export function CommandPalette({ commands, open, onOpenChange }: { commands: Command[]; open: boolean; onOpenChange: (o: boolean) => void }) {
  const bp = useBreakpoint();
  const [query, setQuery] = useState('');
  const [selected, setSelected] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);

  // Global Cmd+K
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); onOpenChange(true); }
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [onOpenChange]);

  // Focus input + handle escape
  useEffect(() => {
    if (!open) return;
    inputRef.current?.focus();
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') { e.preventDefault(); onOpenChange(false); }
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [open, onOpenChange]);

  const filtered = commands.filter((c) => c.label.toLowerCase().includes(query.toLowerCase()));

  const handleKey = (e: React.KeyboardEvent) => {
    if (e.key === 'ArrowDown') { e.preventDefault(); setSelected((s) => Math.min(filtered.length - 1, s + 1)); }
    if (e.key === 'ArrowUp') { e.preventDefault(); setSelected((s) => Math.max(0, s - 1)); }
    if (e.key === 'Enter') { e.preventDefault(); filtered[selected]?.onSelect(); onOpenChange(false); }
  };

  if (!open) return null;

  const isMobile = bp === 'mobile';

  return createPortal(
    <div className="fixed inset-0 z-50" role="dialog" aria-modal="true" aria-label="Command palette">
      <div className="absolute inset-0 bg-black/50" onClick={() => onOpenChange(false)} />
      <div
        className={`
          absolute bg-white shadow-2xl overflow-hidden flex flex-col
          ${isMobile
            ? 'inset-x-0 bottom-0 h-[80dvh] rounded-t-2xl'
            : 'inset-x-4 top-[10vh] mx-auto max-w-xl rounded-xl max-h-[70dvh]'}
        `}
        style={isMobile ? { paddingBottom: 'env(safe-area-inset-bottom)' } : undefined}
      >
        <div className="relative border-b">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-neutral-400" aria-hidden />
          <input
            ref={inputRef}
            type="text"
            value={query}
            onChange={(e) => { setQuery(e.target.value); setSelected(0); }}
            onKeyDown={handleKey}
            placeholder="Search commands"
            aria-label="Search commands"
            autoFocus
            className="block w-full min-h-12 pl-10 pr-12 text-base outline-none"
          />
          <button onClick={() => onOpenChange(false)} aria-label="Close" className="absolute right-2 top-1/2 -translate-y-1/2 flex h-9 w-9 items-center justify-center"><X className="h-4 w-4" /></button>
        </div>
        <div className="flex-1 overflow-y-auto py-2" role="listbox">
          {filtered.length === 0 ? (
            <p className="px-4 py-8 text-center text-sm text-neutral-500">No commands found</p>
          ) : (
            filtered.map((cmd, i) => (
              <button
                key={cmd.id}
                role="option"
                aria-selected={i === selected}
                onClick={() => { cmd.onSelect(); onOpenChange(false); }}
                onMouseEnter={() => setSelected(i)}
                className={`
                  flex w-full items-center justify-between px-4 py-3 text-left min-h-12
                  ${i === selected ? 'bg-blue-50' : 'hover:bg-neutral-50'}
                `}
              >
                <span>{cmd.label}</span>
                {cmd.shortcut && (
                  <kbd className="hidden [@media(any-pointer:fine)]:inline rounded border bg-neutral-50 px-1.5 py-0.5 text-xs font-mono text-neutral-500">{cmd.shortcut}</kbd>
                )}
              </button>
            ))
          )}
        </div>
      </div>
    </div>,
    document.body,
  );
}
